        ResourcePatternResolver resolver = new PathMatchingResourcePatternResolver();
        Resource[] resources = resolver.getResources("classpath*:org/ta4j/core/indicators/**/*.class");
        for (Resource resource : resources) {
            MetadataReader metadataReader = new CachingMetadataReaderFactory().getMetadataReader(resource);
            String className = metadataReader.getClassMetadata().getClassName();

            Class<?> clazz = Class.forName(className);

            // Check if the class is not an interface, not abstract, and has a public constructor
            if (!clazz.isInterface() && 
                !Modifier.isAbstract(clazz.getModifiers()) && 
                hasPublicConstructor(clazz)) {
                // Class has a public constructor, do something with it
            }
        }
    } catch (IOException | ClassNotFoundException e) {
        // Handle exceptions
        e.printStackTrace();
    }
}

public static boolean hasPublicConstructor(@NonNull Class<?> clazz) {
    return Arrays.stream(clazz.getDeclaredConstructors())
